import { useEffect, useState } from "react";
import { collection, limit, onSnapshot, orderBy, query } from "firebase/firestore";
import { db } from "../firebase";

function formatTimestamp(timestamp) {
  if (!timestamp?.toDate) return "Pending";
  return timestamp.toDate().toLocaleString();
}

export default function AgentActionsFeed() {
  const [actions, setActions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const actionsQuery = query(
      collection(db, "agent_actions"),
      orderBy("timestamp", "desc"),
      limit(50)
    );

    const unsubscribe = onSnapshot(actionsQuery, (snapshot) => {
      setActions(snapshot.docs.map((actionDoc) => ({ id: actionDoc.id, ...actionDoc.data() })));
      setLoading(false);
    });

    return unsubscribe;
  }, []);

  return (
    <section className="bg-white p-6 rounded-[20px] shadow-sm border border-[#dbe7f3]">
      <div className="mb-5">
        <h2 className="text-xl font-bold text-[#122033]">Agent Action Log</h2>
        <p className="text-sm text-[#64748b] mt-1">Recent selections from the agent action panel.</p>
      </div>

      {loading ? (
        <p className="text-[#64748b]">Loading actions...</p>
      ) : actions.length === 0 ? (
        <p className="text-[#64748b]">No agent actions logged yet.</p>
      ) : (
        <div className="space-y-3">
          {actions.map((action) => (
            <article key={action.id} className="border border-[#e2e8f0] rounded-[16px] p-4">
              <div className="flex items-start justify-between gap-4">
                <div>
                  <p className="font-bold text-[#122033]">{action.agentName || "Unknown Agent"}</p>
                  <p className="text-sm text-[#334155] mt-1">Action: {action.actionType}</p>
                </div>
                <p className="text-sm text-[#64748b] text-right">{formatTimestamp(action.timestamp)}</p>
              </div>
            </article>
          ))}
        </div>
      )}
    </section>
  );
}
